html.script:
function sp(t){document.getElementById('cp').value=t;}
function clearInput(){document.getElementById('cp').value='';}
function generateDashboard(){
  var p=document.getElementById('cp').value;
  if(!p.trim()){alert('Harap deskripsikan dashboard yang Anda inginkan terlebih dahulu.');return;}

  var q='| makeresults | eval _raw="" | geminianalyze prompt='+JSON.stringify(p)+' role="splunk_dashboard_dev" | table gemini_analysis';

  window.location.href=window.location.origin+'/en-US/app/gemini_soc_assistant/search?q='+encodeURIComponent(q)+'&earliest=-1m&latest=now';
}
